vi.mock('../../src/repositories/ordersRepo');
vi.mock('../../src/repositories/orderDetailsRepo');
vi.mock('../../src/repositories/productsRepo');

import orderRouter from '../../src/routes/order';
import { getOrdersRepository } from '../../src/repositories/ordersRepo';
import { getOrderDetailsRepository } from '../../src/repositories/orderDetailsRepo';
