// ─── POST / (traditional) ─────────────────────────────────────────────────────
describe('POST /orders — traditional creation', () => {
  it('returns 201 with the created order', async () => {
    const payload = {
      branchId: 1,
      orderDate: '2026-03-01T00:00:00Z',
      name: 'New Supply Order',
      description: 'Monthly restock',
      status: 'pending',
    };
    const created = { orderId: 10, ...payload };
    mockOrdersRepo.create.mockResolvedValue(created);

    const res = await request(app).post('/orders').send(payload);

    expect(res.status).toBe(201);
    expect(res.body).toMatchObject({ orderId: 10, name: 'New Supply Order', status: 'pending' });
    expect(mockOrdersRepo.create).toHaveBeenCalledWith(payload);
  });

  it('persists the order (create is called exactly once)', async () => {
    const payload = { branchId: 2, orderDate: '2026-03-01T00:00:00Z', name: 'O', description: 'D', status: 'pending' };
    mockOrdersRepo.create.mockResolvedValue({ orderId: 99, ...payload });

    await request(app).post('/orders').send(payload);

    expect(mockOrdersRepo.create).toHaveBeenCalledTimes(1);
  });
});

// ─── POST / (guest checkout) ──────────────────────────────────────────────────
describe('POST /orders — guest checkout', () => {
  const product1 = { productId: 1, name: 'Widget A', price: 9.99, stockLevel: 20 };
  const product2 = { productId: 2, name: 'Widget B', price: 19.99, stockLevel: 5 };

  it('returns 201 with order and items on successful guest checkout', async () => {
    const payload = {
      customerName: 'Bob',
      customerEmail: 'bob@example.com',
      branchId: 2,
      items: [
        { productId: 1, quantity: 3 },
        { productId: 2, quantity: 1 },
      ],
    };
    const createdOrder = {
      orderId: 20,
      branchId: 2,
      orderDate: '2026-03-02T12:00:00Z',
      name: 'Order from Bob',
      description: 'Guest checkout order',
      status: 'pending',
      customerName: 'Bob',
      customerEmail: 'bob@example.com',
    };
    const detail1 = { orderDetailId: 1, orderId: 20, productId: 1, quantity: 3, unitPrice: 9.99, notes: '' };
    const detail2 = { orderDetailId: 2, orderId: 20, productId: 2, quantity: 1, unitPrice: 19.99, notes: '' };

    mockProductsRepo.checkStock.mockResolvedValue(true);
    mockOrdersRepo.create.mockResolvedValue(createdOrder);
    mockProductsRepo.findById
      .mockResolvedValueOnce(product1)
      .mockResolvedValueOnce(product2);
    mockOrderDetailsRepo.create
      .mockResolvedValueOnce(detail1)
      .mockResolvedValueOnce(detail2);
    mockProductsRepo.decrementStock.mockResolvedValue(undefined);

    const res = await request(app).post('/orders').send(payload);

    expect(res.status).toBe(201);
    expect(res.body).toMatchObject({
      orderId: 20,
      customerName: 'Bob',
      customerEmail: 'bob@example.com',
    });
    expect(res.body.items).toHaveLength(2);
    expect(res.body.items[0]).toMatchObject({ productId: 1, quantity: 3, unitPrice: 9.99 });
    expect(res.body.items[1]).toMatchObject({ productId: 2, quantity: 1, unitPrice: 19.99 });
  });

  it('decrements stock for every item in the checkout', async () => {
    const payload = {
      customerName: 'Carol',
      items: [
        { productId: 1, quantity: 5 },
        { productId: 2, quantity: 2 },
      ],
    };
    const createdOrder = { orderId: 21, branchId: 1, orderDate: '2026-03-02T12:00:00Z', name: 'Order from Carol', description: 'Guest checkout order', status: 'pending' };

    mockProductsRepo.checkStock.mockResolvedValue(true);
    mockOrdersRepo.create.mockResolvedValue(createdOrder);
    mockProductsRepo.findById
      .mockResolvedValueOnce(product1)
      .mockResolvedValueOnce(product2);
    mockOrderDetailsRepo.create.mockResolvedValue({ orderDetailId: 3, orderId: 21, productId: 1, quantity: 5, unitPrice: 9.99, notes: '' });
    mockProductsRepo.decrementStock.mockResolvedValue(undefined);

    await request(app).post('/orders').send(payload);

    expect(mockProductsRepo.decrementStock).toHaveBeenCalledTimes(2);
    expect(mockProductsRepo.decrementStock).toHaveBeenCalledWith(1, 5);
    expect(mockProductsRepo.decrementStock).toHaveBeenCalledWith(2, 2);
  });

  it('returns 400 when a product does not have sufficient stock', async () => {
    const insufficientProduct = { productId: 1, name: 'Widget A', price: 9.99, stockLevel: 2 };
    mockProductsRepo.checkStock.mockResolvedValue(false);
    mockProductsRepo.findById.mockResolvedValue(insufficientProduct);

    const res = await request(app)
      .post('/orders')
      .send({ customerName: 'Dave', items: [{ productId: 1, quantity: 10 }] });

    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
    expect(res.body.error).toMatch(/insufficient stock/i);
    // Order must NOT be created when stock check fails
    expect(mockOrdersRepo.create).not.toHaveBeenCalled();
  });

  it('uses default branchId (1) when no branchId is provided', async () => {
    const createdOrder = { orderId: 30, branchId: 1, orderDate: '2026-03-02T12:00:00Z', name: 'Order from Guest', description: 'Guest checkout order', status: 'pending' };
    mockProductsRepo.checkStock.mockResolvedValue(true);
    mockOrdersRepo.create.mockResolvedValue(createdOrder);
    mockProductsRepo.findById.mockResolvedValue(product1);
    mockOrderDetailsRepo.create.mockResolvedValue({ orderDetailId: 4, orderId: 30, productId: 1, quantity: 2, unitPrice: 9.99, notes: '' });
    mockProductsRepo.decrementStock.mockResolvedValue(undefined);

    await request(app)
      .post('/orders')
      .send({ items: [{ productId: 1, quantity: 2 }] });

    expect(mockOrdersRepo.create).toHaveBeenCalledWith(
      expect.objectContaining({ branchId: 1 }),
    );
  });
});

// ─── PUT /:id ─────────────────────────────────────────────────────────────────
describe('PUT /orders/:id', () => {
  it('returns 200 with the updated order', async () => {
    const updated = { ...baseOrder, status: 'delivered' };
    mockOrdersRepo.update.mockResolvedValue(updated);

    const res = await request(app).put('/orders/1').send({ status: 'delivered' });

    expect(res.status).toBe(200);
    expect(res.body).toMatchObject({ orderId: 1, status: 'delivered' });
  });

  it('passes only the supplied fields to the repository (partial update)', async () => {
    const updated = { ...baseOrder, name: 'Renamed Order' };
    mockOrdersRepo.update.mockResolvedValue(updated);

    await request(app).put('/orders/1').send({ name: 'Renamed Order' });

    expect(mockOrdersRepo.update).toHaveBeenCalledWith(1, { name: 'Renamed Order' });
  });

  it('returns 404 when the order to update does not exist', async () => {
    mockOrdersRepo.update.mockRejectedValue(new NotFoundError('Order', 9999));

    const res = await request(app).put('/orders/9999').send({ status: 'cancelled' });

    expect(res.status).toBe(404);
  });
});

